<?php require_once "app/models/Notification.php"; class NotificationController{private $m;function __construct($db){$this->m=new Notification($db);}function index(){requireLogin(); if(isset($_GET['read']))$this->m->markRead($_GET['read'],$_SESSION['user_id']); if(isset($_GET['delete']))$this->m->delete($_GET['delete'],$_SESSION['user_id']); if(isset($_GET['mark_all']))$this->m->markAllRead($_SESSION['user_id']); $notifications=$this->m->forUser($_SESSION['user_id']); include "app/views/notifications/index.php";}}?>